const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  const input = raw.body || raw;

  const issueId = input.issue_id;
  if (!issueId) throw new Error('Missing issue_id');

  const lat = parseFloat(input.latitude) || 0;
  const lon = parseFloat(input.longitude) || 0;
  const hasCoords = lat !== 0 && lon !== 0;

  let resolvedAddress = input.address || 'Unknown';
  if (hasCoords && resolvedAddress === 'Unknown') {
    try {
      const geocode = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json&addressdetails=1`,
        headers: { 'User-Agent': 'CityReporterApp/1.0' },
        json: true,
        timeout: 10000
      });
      if (geocode?.display_name) resolvedAddress = geocode.display_name;
    } catch (e) {}
  }

  const mapsLink = hasCoords ? `https://maps.google.com/?q=${lat},${lon}` : '';

  const factsDe = [
    `Meldungs-ID: ${issueId}`,
    `Kategorie: ${input.category || 'unbekannt'}`,
    `Schweregrad: ${input.severity || 'unbekannt'}`,
    `KI-Beschreibung: ${input.ai_description || 'keine'}`,
    `Benutzerbeschreibung: ${input.user_description || 'keine'}`,
    `Sicherheitsrisiko: ja`,
    `Ort: ${resolvedAddress}`,
    hasCoords ? `Koordinaten: ${lat}, ${lon}` : '',
    mapsLink ? `Karte: ${mapsLink}` : '',
    `Zuständigkeit (KI-Vorschlag): ${input.authority_type || 'allgemein'}`
  ].filter(Boolean).join('\n');

  const systemPrompt = 'Du bist ein Assistent für eine Bürger-Meldestelle (Stadt/Umwelt). Du verfasst formelle Schreiben an Behörden. Antworte NUR mit gültigem JSON (kein Markdown, kein Kommentar).';

  const userPrompt = `Verfasse ein formelles Schreiben an die zuständige Behörde auf Deutsch (Sie-Form) für die folgende Meldung mit Sicherheitsrisiko.

Das Schreiben soll höflich, sachlich und professionell sein. Verwende einfaches HTML (<p>, <br>, <strong>, <ul><li>) für den Brieftext.

Suche auch nach der zuständigen Behörde / Abteilung in der Region und füge eine realistische E-Mail-Adresse hinzu.

Antwortformat (exakt diese Schlüssel):
{
  "authority_name": "Name der Behörde/Abteilung",
  "authority_email": "realistische E-Mail-Adresse",
  "email_subject": "Betreff des Schreibens",
  "email_body_html": "<p>Formeller Brieftext in HTML</p>"
}

Fakten zur Meldung:
${factsDe}`;

  results.push({
    json: {
      issue_id: issueId,
      callback_url: input.callback_url || null,
      address: resolvedAddress,
      ai_request_body: {
        contents: [{
          role: 'user',
          parts: [{ text: systemPrompt + '\n\n' + userPrompt }]
        }],
        generationConfig: {
          responseMimeType: 'application/json',
          maxOutputTokens: 2048,
          temperature: 0.25
        }
      }
    }
  });
}

return results;

const items = $input.all();
const prepItems = $('Prepare Letter Request').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const prep = prepItems[i]?.json || prepItems[0]?.json || {};
  const gemini = items[i].json;
  const text = gemini.candidates?.[0]?.content?.parts?.[0]?.text || '';

  let draft;
  try {
    draft = JSON.parse(text);
  } catch (e) {
    draft = {
      authority_name: 'Stadtverwaltung',
      authority_email: '',
      email_subject: 'Sicherheitsmeldung ' + prep.issue_id,
      email_body_html: '<p>Die automatische Brieferstellung ist fehlgeschlagen. Bitte prüfen Sie die Meldung manuell.</p>'
    };
  }

  results.push({
    json: {
      issue_id: prep.issue_id,
      callback_url: prep.callback_url,
      subject: draft.email_subject || ('Sicherheitsmeldung ' + prep.issue_id),
      body_html: draft.email_body_html || '<p>(Kein Inhalt)</p>',
      authority_email: draft.authority_email || '',
      authority_name: draft.authority_name || 'Stadtverwaltung'
    }
  });
}

return results;

return $input.all().map(item => ({
  json: {
    success: true,
    issue_id: $('Parse Letter Response').first().json.issue_id,
    message: 'Escalation letter generated and sent to Convex'
  }
}));
